VALUES
  ('social-worker-moex-07850', 'social-worker', 'social-worker-moex-099-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '某青少年社福機構為協助中輟生發展職涯，而規劃準備性多元就業服務方案，希望藉此培養青少年的就業 能力與職業倫理，同時亦期望透過此研究建立該機構未來的青少年就業服務模式。為達成此研究目的，本 研究計畫最適合採用何種研究方法？', '["實驗研究", "調查研究", "行動研究", "非介入性研究（unobtrusive measures）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "01a38a7597b2", "answer_pdf_sha1": "7b44c41cbb23", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "700", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 37, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07851', 'social-worker', 'social-worker-moex-099-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列何者議題適合採用田野研究方法？①校園教學活動  ②中學生髮型公投  ③開放大陸生來臺公聽會', '["參與公部門擴大就業方案的滿意度  ⑤勞工春鬥和秋鬥", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "01a38a7597b2", "answer_pdf_sha1": "7b44c41cbb23", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "700", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 38, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07852', 'social-worker', 'social-worker-moex-099-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '測量誤差的來源包括系統誤差（systematic error）和隨機誤差（random error），下列有關測量誤差的敘述 何者錯誤？', '["文化規範可能造成測量之系統誤差", "當收集回來的資料與原先預定測量的事物有不同即產生隨機誤差", "想要減少系統誤差，可以在設計問卷或量表時，儘量避免有偏見的字眼", "想要減少隨機誤差，可以在設計問卷或量表時，儘量用受訪者能瞭解的字句"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "01a38a7597b2", "answer_pdf_sha1": "7b44c41cbb23", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "700", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 39, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07853', 'social-worker', 'social-worker-moex-099-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '把抽象的定義予以實體化，使之可以用測量的方式來衡量此概念的過程稱為：', '["概念化（conceptualization）", "操作化（operationalization）", "觀測化（observationalization）", "有效化（effectivity）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "01a38a7597b2", "answer_pdf_sha1": "7b44c41cbb23", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "700", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 40, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07854', 'social-worker', 'social-worker-moex-099-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '陳教授研究65歲以上的老人，發現年紀越大的老人，過得越快樂。因此，陳教授提出結論，認為65歲 以下的人口群，也同樣會隨著年紀的增長，而過得更加快樂。請問陳教授可能犯了下列何種研究錯誤？', '["選擇性觀察", "過度推論", "過度樂觀", "不正確的觀察"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "9313d97acd83", "answer_pdf_sha1": "6ed4ed48e43b", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "700", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 1, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07855', 'social-worker', 'social-worker-moex-099-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '某一青少年工作者想要運用精確與客觀的研究方法來檢測某一介入方案（intervention program）是否能減 少青少年的偏差行為。請問該研究所遵行的典範為：', '["後現代主義", "詮釋主義", "實證主義", "批判社會科學"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "9313d97acd83", "answer_pdf_sha1": "6ed4ed48e43b", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "700", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 2, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07856', 'social-worker', 'social-worker-moex-099-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '某醫務社會工作師在星期六對參與某一病友支持團體的案主進行社會功能量表的施測。隔了一個星期，該 社會工作師又對該病友團體的同一群案主進行同一份社會功能量表的施測。請問，該社會工作師是想要檢 測該量表的：', '["內部一致性信度", "再測信度", "專家效度", "預測效度"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "9313d97acd83", "answer_pdf_sha1": "6ed4ed48e43b", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "700", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 3, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07857', 'social-worker', 'social-worker-moex-099-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '一般而言，當樣本數增加時：', '["抽樣誤差會減少", "抽樣誤差會增加", "抽樣誤差會消失", "抽樣誤差會維持不變"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "9313d97acd83", "answer_pdf_sha1": "6ed4ed48e43b", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "700", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 4, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07858', 'social-worker', 'social-worker-moex-099-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '某研究者針對2000年從某一個療養院出院的案主，做連續10年的追蹤調查，一直到2010年，以瞭解同 一群案主們在出院後的10年內，其每一年的社會功能是否有所變化。請問該研究是一種：', '["橫斷性研究（cross-sectional study）", "世代研究（Cohort study）", "趨勢研究（Trend study）", "固定名單研究（panel study）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "9313d97acd83", "answer_pdf_sha1": "6ed4ed48e43b", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "700", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 5, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07859', 'social-worker', 'social-worker-moex-099-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '質性研究：', '["強調精確與機率", "強調深層的意義", "不能和量化研究整合在同一個研究之中", "不需要有信效度"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "9313d97acd83", "answer_pdf_sha1": "6ed4ed48e43b", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "700", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 6, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
